const DIRECT_IO_ALIGN: usize = 512;

fn check_direct_io(file: &Arc<dyn File>, addr: usize, len: usize, offset: usize) -> SysResult<()> {
    if len == 0 || !file.flags().contains(OpenFlags::O_DIRECT) {
        return Ok(());
    }

    if addr % DIRECT_IO_ALIGN != 0 || len % DIRECT_IO_ALIGN != 0 || offset % DIRECT_IO_ALIGN != 0 {
        return Err(SysError::EINVAL);
    }

    Ok(())
}

/// The `open`() system call opens the file specified by `pathname`.  If the specified file does not ex‐
