#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum CommandOutcome {
    Exited(i32),
    Timeout,
    ForkFailed,
}

fn waitpid_timeout(pid: isize, label: &str, timeout_ms: usize) -> CommandOutcome {
    let mut result: i32 = 0;
    let mut waited_ms = 0;
    loop {
        let ret = waitpid(pid, &mut result, WNOHANG);
        if ret == pid {
            return CommandOutcome::Exited(result);
        }
        if ret < 0 {
            return CommandOutcome::Exited(result);
        }
        if timeout_ms > 0 && waited_ms >= timeout_ms {
            println!("ABORT COMMAND {}: timeout_ms={}", label, timeout_ms);
            kill(-pid, SIGKILL);
            kill(pid, SIGKILL);
            for _ in 0..20 {
                let ret = waitpid(pid, &mut result, WNOHANG);
                if ret == pid || ret < 0 {
                    return CommandOutcome::Timeout;
                }
                sleep(50);
            }
            return CommandOutcome::Timeout;
        }
        sleep(POLL_INTERVAL_MS);
        waited_ms += POLL_INTERVAL_MS;
    }
}

