    timer.set_waker_callback(take_waker().await);
    TIMER_MANAGER.add_timer(timer);
    osfuture::suspend_now().await;
    let now = get_time_duration();
    if expire > now {
        expire - now
    } else {
        Duration::ZERO
    }
}

