            let mut user_ptr = UserReadPtr::<u8>::new(ptr, &addr_space);
            let string = user_ptr
                .read_c_string(PATH_LEMGTH)?
                .into_string()
                .map_err(|_| SysError::EINVAL)?;
            args.push(string);
