    let filepath = dentry.path();
    let expath = filepath.rsplit_once('/').map(|x| x.0).unwrap_or("");
    let argpath = format!(
        "PATH={}:/bin:/sbin:/usr/bin:/usr/local/bin:/usr/local/sbin:ltp/testcases/bin:",
        expath
    );
    envs.push(argpath);

    let arghome = "HOME=/";
    envs.push(arghome.to_string());

    log::info!("[sys_execve]: open file {}", dentry.path());
    let file = <dyn File>::open(dentry)?;

    let mut name = String::new();

    // DEBUG
    args.iter_mut().for_each(|arg| {
        *arg = arg.replace("mkfs.ext3", "mkfs.ext2");
        *arg = arg.replace("mkfs.ext4", "mkfs.ext2");
        *arg = arg.replace("mkfs.exfat", "mkfs.ext2");
        *arg = arg.replace("mkfs.bcachefs", "mkfs.ext2");
        *arg = arg.replace("mkfs.btrfs", "mkfs.ext2");
        *arg = arg.replace("mkfs.xfs", "mkfs.ext2");
    });

    args.iter().for_each(|arg| {
        name.push_str(arg);
        name.push(' ');
    });

    let result = task.execve(file.clone(), args.clone(), envs.clone(), name);
    if result == Err(SysError::ENOEXEC) {
        let mut first_line = vec![0; 128];
        file.seek(config::vfs::SeekFrom::Start(0))?;
        file.read(&mut first_line).await?;
        if let Some(index) = first_line.iter().position(|&b| b == b'\n') {
            first_line.truncate(index);
        }

        let interpreter_cmd = String::from_utf8(first_line).map_or(String::from("/bin/sh"), |s| {
            s.strip_prefix("#!")
                .map_or(String::from("/bin/sh"), |s| s.trim().to_string())
        });

        let mut interpreter_args: Vec<String> = interpreter_cmd
            .split_whitespace()
            .map(String::from)
            .collect();
        interpreter_args.extend(args);
        if interpreter_args[0].ends_with("bash") {
            // We don't have bash, so we substitute it with sh as a workaround
            interpreter_args[0] = String::from("/bin/sh");
        }

        let interpreter_path = interpreter_args[0].clone();

        log::info!("[sys_execve]: execute as a script: {:?}", interpreter_args);

        let interpreter_dentry = {
            let cwd = task.cwd().lock().clone();
            let path = Path::new(cwd, interpreter_path.clone());
            let dentry = path.walk()?;
            if !dentry.is_negative() && dentry.inode().unwrap().inotype() == InodeType::SymLink {
                Path::resolve_symlink_through(dentry)?
            } else {
                dentry
            }
        };
        if interpreter_dentry.is_negative() {
            log::warn!("[sys_execve]: interpreter not found: {}", interpreter_path);
            return Err(SysError::ENOENT);
        }

        let interpreter_file = <dyn File>::open(interpreter_dentry)?;
        let cmdline = interpreter_args.join(" ");
        task.execve(interpreter_file, interpreter_args, envs, cmdline)?;
    } else if let Err(e) = result {
        return Err(e);
    }

    if let Some(parent) = task.vfork_parent.clone() {
        if let Some(task) = parent.upgrade() {
            task.wake();
        }
    }

    Ok(0)

use core::{
    cell::UnsafeCell,
    marker::PhantomData,
    ops::{Deref, DerefMut},
    sync::atomic::{AtomicBool, Ordering},
};

use super::MutexSupport;

struct MutexGuard<'a, T: ?Sized, S: MutexSupport> {
    mutex: &'a SpinMutex<T, S>,
    support_guard: S::GuardData,
}

/// `SpinMutex` can include different `MutexSupport` type
#[derive(Debug)]
pub struct SpinMutex<T: ?Sized, S: MutexSupport> {
    // debug_cnt: UnsafeCell<usize>,
    lock: AtomicBool,
    _marker: PhantomData<S>,
    data: UnsafeCell<T>,
}

// 禁止Mutex跨越await导致死锁或无意义阻塞
impl<T: ?Sized, S: MutexSupport> !Sync for MutexGuard<'_, T, S> {}
impl<T: ?Sized, S: MutexSupport> !Send for MutexGuard<'_, T, S> {}

unsafe impl<T: ?Sized + Send, S: MutexSupport> Sync for SpinMutex<T, S> {}
unsafe impl<T: ?Sized + Send, S: MutexSupport> Send for SpinMutex<T, S> {}

impl<T, S: MutexSupport> SpinMutex<T, S> {
    /// Construct a SpinMutex
    pub const fn new(user_data: T) -> Self {
        SpinMutex {
            lock: AtomicBool::new(false),
            _marker: PhantomData,
            data: UnsafeCell::new(user_data),
            // debug_cnt: UnsafeCell::new(0),
        }
    }
    /// Wait until the lock looks unlocked before retrying
    #[inline(always)]
    fn wait_unlock(&self) {
        let mut try_count = 0usize;
        while self.lock.load(Ordering::SeqCst) {
            core::hint::spin_loop();
            try_count += 1;
            if try_count == 0x10000000 {
                log::error!("dead lock!!");
                panic!("Mutex: deadlock detected! try_count > {:#x}\n", try_count);
            }
        }
    }
    /// lock
    #[inline(always)]
    pub fn lock(&self) -> impl DerefMut<Target = T> + '_ {
        let support_guard = S::before_lock();

        loop {
            // logger::lprintln!(
            //     "Lock address: {:p}, value: {}",
            //     &self.lock,
            //     self.lock.load(Ordering::Relaxed)
            // );
            self.wait_unlock();

            if self
                .lock
                .compare_exchange(false, true, Ordering::SeqCst, Ordering::Relaxed)
                .is_ok()
            {
                // logger::lprintln!("one lock");
                break;
            }
        }
        MutexGuard {
            mutex: self,
            support_guard,
        }
    }

    /// # Safety
    ///
    /// This is highly unsafe.
    /// You should ensure that context switch won't happen during
    /// the locked data's lifetime.
    #[inline(always)]
    pub unsafe fn sent_lock(&self) -> impl DerefMut<Target = T> + '_ {
        SendWrapper::new(self.lock())
    }
}

impl<T: ?Sized, S: MutexSupport> Deref for MutexGuard<'_, T, S> {
    type Target = T;
    #[inline(always)]
    fn deref(&self) -> &T {
        unsafe { &*self.mutex.data.get() }
    }
}

impl<T: ?Sized, S: MutexSupport> DerefMut for MutexGuard<'_, T, S> {
    #[inline(always)]
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.mutex.data.get() }
    }
}

impl<T: ?Sized, S: MutexSupport> Drop for MutexGuard<'_, T, S> {
    /// The dropping of the MutexGuard will release the lock it was created from.
    #[inline(always)]
    fn drop(&mut self) {
        // debug_assert!(self.mutex.lock.load(Ordering::Relaxed));
        self.mutex.lock.store(false, Ordering::Release);
        S::after_unlock(&mut self.support_guard);
    }
}

/// A wrapper for a data structure that be sent between threads
pub struct SendWrapper<T>(pub T);

impl<T> SendWrapper<T> {
    pub fn new(data: T) -> Self {
        SendWrapper(data)
    }
}

unsafe impl<T> Send for SendWrapper<T> {}
unsafe impl<T> Sync for SendWrapper<T> {}

impl<T: Deref> Deref for SendWrapper<T> {
    type Target = T::Target;
    #[inline(always)]
    fn deref(&self) -> &Self::Target {
        self.0.deref()
    }
}

impl<T: DerefMut> DerefMut for SendWrapper<T> {
    #[inline(always)]
    fn deref_mut(&mut self) -> &mut Self::Target {
        self.0.deref_mut()
    }
}

